CREATE TYPE "MetricStatus" AS ENUM ('DRAFT','PUBLISHED','ARCHIVED');
CREATE TYPE "MetricAggregation" AS ENUM ('COUNT','SUM','AVERAGE','MIN','MAX','PERCENTAGE','RATIO','WEIGHTED_SCORE','FORMULA');
CREATE TYPE "AggregationJobStatus" AS ENUM ('PENDING','RUNNING','SUCCEEDED','FAILED','CANCELLED');
CREATE TABLE "MetricDefinition" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"valueType" TEXT NOT NULL,"unit" TEXT,"status" "MetricStatus" NOT NULL DEFAULT 'DRAFT',"activeVersionId" TEXT,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "MetricVersion" ("id" TEXT PRIMARY KEY,"definitionId" TEXT NOT NULL,"version" INTEGER NOT NULL,"aggregation" "MetricAggregation" NOT NULL,"formula" JSONB NOT NULL,"dimensions" TEXT[] NOT NULL,"precision" INTEGER NOT NULL DEFAULT 2,"publishedAt" TIMESTAMP(3),"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "MetricSnapshot" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"definitionId" TEXT NOT NULL,"versionId" TEXT NOT NULL,"value" DOUBLE PRECISION NOT NULL,"periodStart" TIMESTAMP(3) NOT NULL,"periodEnd" TIMESTAMP(3) NOT NULL,"grain" TEXT NOT NULL,"dimensions" JSONB NOT NULL DEFAULT '{}',"calculatedById" TEXT,"calculatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AnalyticsFact" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"factType" TEXT NOT NULL,"sourceEntityType" TEXT NOT NULL,"sourceEntityId" TEXT NOT NULL,"occurredAt" TIMESTAMP(3) NOT NULL,"measures" JSONB NOT NULL,"dimensions" JSONB NOT NULL,"sourceEventId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "DashboardDefinition" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "DashboardWidget" ("id" TEXT PRIMARY KEY,"dashboardId" TEXT NOT NULL,"metricDefinitionId" TEXT,"title" TEXT NOT NULL,"type" TEXT NOT NULL,"config" JSONB NOT NULL DEFAULT '{}',"position" INTEGER NOT NULL);
CREATE TABLE "AggregationJob" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"metricDefinitionId" TEXT,"grain" TEXT NOT NULL,"periodStart" TIMESTAMP(3) NOT NULL,"periodEnd" TIMESTAMP(3) NOT NULL,"status" "AggregationJobStatus" NOT NULL DEFAULT 'PENDING',"processedCount" INTEGER NOT NULL DEFAULT 0,"error" TEXT,"initiatedById" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "MetricDefinition_organizationId_key_key" ON "MetricDefinition"("organizationId","key"); CREATE INDEX "MetricDefinition_organizationId_status_idx" ON "MetricDefinition"("organizationId","status");
CREATE UNIQUE INDEX "MetricVersion_definitionId_version_key" ON "MetricVersion"("definitionId","version");
CREATE INDEX "MetricSnapshot_organizationId_definitionId_periodStart_idx" ON "MetricSnapshot"("organizationId","definitionId","periodStart");
CREATE INDEX "AnalyticsFact_organizationId_factType_occurredAt_idx" ON "AnalyticsFact"("organizationId","factType","occurredAt"); CREATE INDEX "AnalyticsFact_organizationId_sourceEntityType_sourceEntityId_idx" ON "AnalyticsFact"("organizationId","sourceEntityType","sourceEntityId");
CREATE UNIQUE INDEX "DashboardDefinition_organizationId_key_key" ON "DashboardDefinition"("organizationId","key"); CREATE INDEX "DashboardWidget_dashboardId_position_idx" ON "DashboardWidget"("dashboardId","position"); CREATE INDEX "AggregationJob_organizationId_status_createdAt_idx" ON "AggregationJob"("organizationId","status","createdAt");
ALTER TABLE "MetricDefinition" ADD CONSTRAINT "MetricDefinition_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "MetricVersion" ADD CONSTRAINT "MetricVersion_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "MetricDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "MetricSnapshot" ADD CONSTRAINT "MetricSnapshot_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "MetricSnapshot" ADD CONSTRAINT "MetricSnapshot_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "MetricDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "MetricSnapshot" ADD CONSTRAINT "MetricSnapshot_versionId_fkey" FOREIGN KEY ("versionId") REFERENCES "MetricVersion"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "AnalyticsFact" ADD CONSTRAINT "AnalyticsFact_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "DashboardDefinition" ADD CONSTRAINT "DashboardDefinition_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "DashboardWidget" ADD CONSTRAINT "DashboardWidget_dashboardId_fkey" FOREIGN KEY ("dashboardId") REFERENCES "DashboardDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "DashboardWidget" ADD CONSTRAINT "DashboardWidget_metricDefinitionId_fkey" FOREIGN KEY ("metricDefinitionId") REFERENCES "MetricDefinition"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "AggregationJob" ADD CONSTRAINT "AggregationJob_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "AggregationJob" ADD CONSTRAINT "AggregationJob_metricDefinitionId_fkey" FOREIGN KEY ("metricDefinitionId") REFERENCES "MetricDefinition"("id") ON DELETE SET NULL ON UPDATE CASCADE;
